async (page) => {
  // Run further away - south and west, toward Mudwich town
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 188, y: 155});
  await page.waitForTimeout(4000);
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return { hp: gs.player_stats?.hp, max_hp: gs.player_stats?.max_hp, pos: gs.player_position, dead: gs.ui_state?.is_dead };
  });
  return JSON.stringify(state);
}

